import { Vex } from '@vex_dev/sdk';
import { createMastraAgent } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const underwritingAgent = createMastraAgent({
  workflow: async (input, context) => {
    // Vex middleware validates all step transitions
    const trace = await vex.trace.start('underwriting_workflow', { policyholderId: input.id });

    const riskScore = await workflowStep1(input);
    await vex.validate('risk_score_valid', {
      value: riskScore,
      schema: { min: 0, max: 1000, type: 'number' },
      context: trace
    });

    const decision = await underwritingDecision(riskScore);
    await trace.end({ decision, explainability: generateExplanation(decision) });
    return decision;
  }
});

import { VexGuard } from '@vex_dev/sdk';

const insuranceGuard = new VexGuard([
  {
    name: 'credit_data_valid',
    schema: {
      ssn: { format: 'ssn', required: true },
      creditScore: { min: 300, max: 850 },
      inquiries: { max: 10 }
    },
    blockOnFail: true,
    tags: ['fcra', 'underwriting']
  },
  {
    name: 'protected_class_proxy',
    pattern: /\b(urban|postal|ethnic)\b/i,
    risk: 'discrimination',
    blockOnFail: true
  }
]);

// In Mastra tool handler
const creditTool = async (params) => {
  const data = await fetchCreditData(params);
  await insuranceGuard.validate('credit_tool_output', data);
  return data;
};

const memoryGuard = async (retrievedContext: any, sessionId: string) => {
  const freshnessCheck = await vex.validate('policy_freshness', {
    data: retrievedContext,
    rules: [
      {
        field: 'lastUpdated',
        maxAgeDays: 30,
        error: 'stale_policy_data'
      },
      {
        field: 'policyStatus',
        allowed: ['active', 'pending'],
        error: 'inactive_policy_used'
      }
    ],
    session: sessionId,
    tags: ['gdpr', 'ccpa']
  });

  if (!freshnessCheck.valid) {
    await vex.incident.create({
      type: 'stale_context_injection',
      sessionId,
      data: retrievedContext
    });
    throw new Error('Stale policy context detected');
  }
  return retrievedContext;
};
